SELECT [DDT_Picking Header].No_, [DDT_Picking Header].[Sell-to Customer No_], [DDT_Picking Header].[Bill-to Customer No_], [DDT_Picking Header].[Bill-to Name], [DDT_Picking Line].Type, [DDT_Picking Line_1].No_, [DDT_Picking Line_1].Description, Val([ddt_picking line.Quantity]) AS qty, [DDT_Picking Line].[Variable Code 01] AS Color, [DDT_Picking Line].[Variable Code 02] AS [Size], [DDT_Picking Line_1].[Assortment Code], [DDT_Picking Line].[Original Line No_], IIf([ddt_picking line_1.type]=20,Val([ddt_picking line_1.Quantity]),"") AS ass_qty
FROM ([DDT_Picking Line] AS [DDT_Picking Line_1] INNER JOIN [DDT_Picking Line] ON ([DDT_Picking Line].[Original Line No_] = [DDT_Picking Line_1].[Line No_]) AND ([DDT_Picking Line_1].[Document No_] = [DDT_Picking Line].[Document No_])) INNER JOIN [DDT_Picking Header] ON ([DDT_Picking Line].[Document No_] = [DDT_Picking Header].No_) AND ([DDT_Picking Line].[Document Type] = [DDT_Picking Header].[Document Type])
WHERE ((([DDT_Picking Header].No_)=[forms]![principale]![filtroddt]) AND (([DDT_Picking Line].Type)=2));

